+    #[test]
+    fn inspect_shows_type_and_fields_when_available() {
+        let value = Inner {
+            name: "Zed".to_string(),
+            values: vec![1, 2, 3],
+        };
+        let console = test_console(60);
+        let inspect = Inspect::new(&value);
+        let plain = console.export_renderable_text(&inspect);
+        insta::assert_snapshot!(plain);
+    }
+}

